const EncyclopediaEngine = {categories:[{id:"earthquake",name:"地震",icon:"🌍",color:"#FF6B35"},{id:"fire",name:"火灾",icon:"🔥",color:"#FF5252"},{id:"flood",name:"洪水",icon:"🌊",color:"#2196F3"},{id:"typhoon",name:"台风",icon:"🌪️",color:"#9C27B0"},{id:"lightning",name:"雷电",icon:"⚡",color:"#FFD700"},{id:"landslide",name:"泥石流",icon:"🏔️",color:"#795548"},{id:"tornado",name:"龙卷风",icon:"🌀",color:"#607D8B"},{id:"snowstorm",name:"暴雪",icon:"❄️",color:"#90CAF9"},{id:"gas",name:"燃气泄漏",icon:"💨",color:"#4CAF50"},{id:"elevator",name:"电梯故障",icon:"🛗",color:"#FF9800"}],articles:{earthquake:[{title:"什么是地震？",icon:"📖",content:"地震是地壳快速释放能量产生的振动。<br><br>地球上每年发生约<strong>500万次</strong>地震，但大多数太小感觉不到。<br><br>地震的强度用<strong>里氏震级</strong>表示，每增加1级，能量增加约<strong>32倍</strong>。"},{title:"地震的成因",icon:"🔬",content:"地震主要由<strong>板块运动</strong>引起：<br><br>🔹 地球表面由多个板块组成<br>🔹 板块之间相互挤压、碰撞<br>🔹 能量积累到极限时突然释放<br>🔹 形成地震波向四周传播<br><br>中国位于<strong>环太平洋地震带</strong>和<strong>欧亚地震带</strong>之间，地震频繁。"},{title:"地震前兆",icon:"⚠️",content:"地震前可能出现一些异常现象：<br><br>🔹 地下水变浑、水位变化<br>🔹 动物行为异常（鸡飞狗跳）<br>🔹 地面出现裂缝或隆起<br>🔹 井水冒泡、变味<br><br>注意：这些现象不一定表示地震要来，但值得警惕！"},{title:"地震时怎么办",icon:"🏃",content:"<strong>室内：</strong><br>🔹 躲在桌子下面，抓住桌腿<br>🔹 远离窗户、吊灯、书架<br>🔹 用枕头保护头部<br>🔹 不要跳楼！<br><br><strong>室外：</strong><br>🔹 远离建筑物、电线杆<br>🔹 蹲下，保护头部<br>🔹 注意避开广告牌、玻璃"},{title:"地震后注意事项",icon:"🏥",content:"地震停止后：<br><br>🔹 检查自己和家人是否受伤<br>🔹 关闭燃气、电源<br>🔹 不要使用明火<br>🔹 收听官方广播获取信息<br>🔹 注意余震（可能比主震更危险）<br>🔹 不要回到受损建筑内"},{title:"家庭防震准备",icon:"🏠",content:"每个家庭都应该：<br><br>🔹 准备<strong>应急包</strong>（水、食物、手电筒、急救品）<br>🔹 固定家具（书架、衣柜）<br>🔹 确认安全避难位置<br>🔹 参加防震演练<br>🔹 学习急救知识<br><br>记住：<strong>准备充分 = 生存机会更大</strong>"}],fire:[{title:"火灾的分类",icon:"📖",content:"火灾按燃烧物分为5类：<br><br>🔹 <strong>A类</strong>：固体火灾（木材、纸张）<br>🔹 <strong>B类</strong>：液体火灾（汽油、酒精）<br>🔹 <strong>C类</strong>：气体火灾（天然气、煤气）<br>🔹 <strong>D类</strong>：金属火灾（钠、镁）<br>🔹 <strong>E类</strong>：电气火灾（电器、电线）<br><br>不同类型火灾需要不同灭火方式！"},{title:"灭火器的使用",icon:"🧯",content:"记住<strong>四字口诀：提、拔、瞄、压</strong><br><br>🔹 <strong>提</strong>起灭火器<br>🔹 <strong>拔</strong>掉保险销<br>🔹 <strong>瞄</strong>准火焰根部<br>🔹 <strong>压</strong>下压把喷射<br><br>站在<strong>上风向</strong>，距离火焰<strong>2-3米</strong>处喷射。"},{title:"火场逃生技巧",icon:"🏃",content:"<strong>火场逃生要点：</strong><br><br>🔹 用<strong>湿毛巾</strong>捂住口鼻<br>🔹 <strong>弯腰低姿</strong>前行（烟气上升）<br>🔹 沿墙壁摸索前进<br>🔹 不要乘坐电梯！<br>🔹 开门前先摸门把手（烫手不开）<br>🔹 被困时到窗口呼救，等待救援"},{title:"家庭防火知识",icon:"🏠",content:"家庭防火要点：<br><br>🔹 不要超负荷用电<br>🔹 离开时关闭燃气阀门<br>🔹 不在床上吸烟<br>🔹 电动车不要在室内充电<br>🔹 保持消防通道畅通<br>🔹 安装烟雾报警器<br><br>火灾致死原因：<strong>80%是烟气窒息</strong>，不是烧伤！"},{title:"高楼火灾逃生",icon:"🏢",content:"高楼火灾特别危险：<br><br>🔹 不要盲目跳楼！<br>🔹 向下逃生（烟气向上）<br>🔹 如果楼梯被堵，退回房间<br>🔹 用湿布堵住门缝<br>🔹 到窗口挥动鲜艳衣物求救<br>🔹 有条件时用床单结绳逃生<br><br>记住：<strong>生命第一，财物第二</strong>"},{title:"学校防火须知",icon:"🏫",content:"学校防火要点：<br><br>🔹 不携带易燃易爆物品进校<br>🔹 不私拉乱接电线<br>🔹 实验课遵守操作规程<br>🔹 熟悉疏散路线和安全出口<br>🔹 参加消防演练要认真<br>🔹 发现火灾隐患及时报告<br><br>火灾报警电话：<strong>119</strong>"}],flood:[{title:"洪水的成因",icon:"📖",content:"洪水主要由以下原因引起：<br><br>🔹 暴雨（最常见）<br>🔹 台风带来的强降雨<br>🔹 冰雪融化<br>🔹 河道堵塞<br>🔹 海啸<br><br>中国是世界上<strong>洪涝灾害最严重</strong>的国家之一。"},{title:"洪水预警信号",icon:"⚠️",content:'洪水预警分四级：<br><br>🔹 <strong style="color:#4CAF50">蓝色</strong>：水位可能超警戒线<br>🔹 <strong style="color:#FFEB3B">黄色</strong>：水位超警戒线<br>🔹 <strong style="color:#FF9800">橙色</strong>：水位超保证水位<br>🔹 <strong style="color:#f44336">红色</strong>：水位超历史最高<br><br>收到预警要<strong>立即转移</strong>！'},{title:"洪水来临时怎么办",icon:"🏃",content:"<strong>来不及转移时：</strong><br><br>🔹 向高处转移（楼顶、山坡）<br>🔹 不要游泳逃生！<br>🔹 抓住固定物体<br>🔹 发出求救信号<br>🔹 不要靠近电线杆、变压器<br><br>记住：<strong>水深超过膝盖就不要强行通过</strong>！"},{title:"城市内涝应对",icon:"🏙️",content:"城市内涝时：<br><br>🔹 不要进入地下空间（地铁、地下车库）<br>🔹 远离积水路段<br>🔹 注意井盖被冲开<br>🔹 不要靠近路灯、电线杆<br>🔹 车辆熄火后立即弃车<br><br>城市内涝最常见的危险：<strong>触电</strong>和<strong>溺水</strong>"},{title:"灾后防疫知识",icon:"🏥",content:"洪水过后要注意：<br><br>🔹 不喝生水，要煮沸或消毒<br>🔹 不吃被洪水浸泡的食物<br>🔹 清理环境，防止蚊虫滋生<br>🔹 穿胶鞋防止划伤感染<br>🔹 出现发热、腹泻及时就医<br><br>洪水后最危险的不是水，是<strong>疾病</strong>！"}],typhoon:[{title:"什么是台风",icon:"📖",content:"台风是发生在<strong>西北太平洋</strong>的热带气旋。<br><br>风力等级：<br>🔹 6-7级：热带低压<br>🔹 8-9级：热带风暴<br>🔹 10-11级：强热带风暴<br>🔹 12-13级：台风<br>🔹 14-15级：强台风<br>🔹 16级以上：超强台风"},{title:"台风来了怎么办",icon:"🏃",content:"<strong>台风来临前：</strong><br>🔹 关好门窗，加固易倒物品<br>🔹 准备应急物资<br>🔹 不要去海边、河边<br><br><strong>台风来临时：</strong><br>🔹 待在室内，远离窗户<br>🔹 不要外出<br>🔹 注意收听天气预报<br><br><strong>台风过后：</strong><br>🔹 注意积水和倒塌物"},{title:"台风预警信号",icon:"⚠️",content:'台风预警分四级：<br><br>🔹 <strong style="color:#4CAF50">蓝色</strong>：24小时内可能影响<br>🔹 <strong style="color:#FFEB3B">黄色</strong>：24小时内将影响<br>🔹 <strong style="color:#FF9800">橙色</strong>：12小时内将严重影响<br>🔹 <strong style="color:#f44336">红色</strong>：6小时内将特别严重影响<br><br>预警发布时要<strong>停止户外活动</strong>！'}],lightning:[{title:"雷电的形成",icon:"📖",content:"雷电是<strong>云层之间</strong>或<strong>云层与地面</strong>之间的放电现象。<br><br>形成条件：<br>🔹 强烈的上升气流<br>🔹 充足的水汽<br>🔹 不稳定的大气层<br><br>一次闪电温度可达<strong>30000°C</strong>，是太阳表面温度的5倍！"},{title:"防雷知识",icon:"⚡",content:"<strong>室内防雷：</strong><br>🔹 关好门窗<br>🔹 远离水管、暖气管<br>🔹 不要使用电话<br>🔹 拔掉电器插头<br><br><strong>室外防雷：</strong><br>🔹 不要在大树下避雨<br>🔹 不要打金属伞<br>🔹 蹲下，双脚并拢<br>🔹 不要骑自行车、摩托车"}],landslide:[{title:"泥石流的形成",icon:"📖",content:"泥石流是<strong>暴雨</strong>引发的山体滑坡和泥沙混合物。<br><br>形成条件：<br>🔹 陡峭的地形<br>🔹 松散的土石<br>🔹 强降雨<br><br>泥石流速度可达<strong>每秒10米以上</strong>，破坏力极强！"},{title:"泥石流逃生",icon:"🏃",content:"<strong>发现泥石流时：</strong><br><br>🔹 立即向<strong>垂直方向</strong>的高处跑<br>🔹 不要顺着泥石流方向跑！<br>🔹 不要在低洼处停留<br>🔹 不要躲在树下<br><br>记住：<strong>向两侧高处跑</strong>，不要顺沟跑！"}],tornado:[{title:"龙卷风知识",icon:"📖",content:"龙卷风是<strong>最强的风</strong>，风速可达<strong>每小时500公里</strong>。<br><br>特点：<br>🔹 持续时间短（通常几分钟）<br>🔹 影响范围小<br>🔹 破坏力极大<br>🔹 可以把汽车吹上天<br><br>中国<strong>长三角地区</strong>龙卷风较多。"},{title:"龙卷风来了怎么办",icon:"🏃",content:"<strong>室内：</strong><br>🔹 远离窗户<br>🔹 躲在地下室或一楼<br>🔹 用厚毯子盖住身体<br><br><strong>室外：</strong><br>🔹 找低洼处趴下<br>🔹 远离树木、车辆<br>🔹 不要躲在桥下<br><br>龙卷风预警时间很短，要<strong>立即行动</strong>！"}],snowstorm:[{title:"暴雪的危害",icon:"📖",content:"暴雪会带来：<br><br>🔹 交通瘫痪<br>🔹 电力中断<br>🔹 房屋压塌<br>🔹 冻伤和失温<br><br>暴雪时能见度可能<strong>低于50米</strong>，非常危险！"},{title:"暴雪防护",icon:"❄️",content:"<strong>暴雪防护要点：</strong><br><br>🔹 准备足够的食物和水<br>🔹 储备保暖衣物<br>🔹 保持通讯畅通<br>🔹 不要外出<br>🔹 注意防滑<br>🔹 防止一氧化碳中毒<br><br>失温症状：颤抖、说话困难、意识模糊"}],gas:[{title:"燃气泄漏怎么办",icon:"💨",content:"发现燃气泄漏时：<br><br>🔹 <strong>立即关闭阀门</strong><br>🔹 打开门窗通风<br>🔹 <strong>不要开灯、不要打电话</strong>（会产生火花）<br>🔹 到室外拨打燃气公司电话<br>🔹 不要使用明火<br><br>记住：<strong>关阀、开窗、撤离、报警</strong>"}],elevator:[{title:"电梯故障应对",icon:"🛗",content:"电梯故障时：<br><br>🔹 <strong>保持冷静</strong>，不要惊慌<br>🔹 按下<strong>紧急呼叫按钮</strong><br>🔹 拨打电梯内标注的维修电话<br>🔹 <strong>不要扒门</strong>！<br>🔹 <strong>不要从天花板爬出</strong>！<br>🔹 电梯有通风，不会窒息<br><br>记住：电梯是<strong>最安全的交通工具</strong>之一，故障时等待救援最安全。"}]},extraArticles:{earthquake:[{title:"地震预警系统",icon:"📡",content:"中国已建成全球最大的地震预警网：<br><br>🔹 <strong>成都高新减灾研究所</strong>研发了地震预警系统<br>🔹 利用电磁波比地震波快的原理<br>🔹 可提前<strong>几秒到几十秒</strong>发出预警<br>🔹 手机APP、电视、广播均可接收<br><br>⚠️ 预警≠预测，是地震发生后的快速警报！"},{title:"建筑抗震标准",icon:"🏗️",content:"中国建筑抗震设防标准：<br><br>🔹 一般建筑：<strong>7度</strong>设防<br>🔹 学校、医院：<strong>8度</strong>设防（更严格）<br>🔹 核电站：<strong>9度</strong>设防<br><br>抗震设计的核心原则：<br>🔹 <strong>小震不坏</strong>：日常小地震不影响使用<br>🔹 <strong>中震可修</strong>：中等地震可修复<br>🔹 <strong>大震不倒</strong>：大地震不整体坍塌"}],fire:[{title:"消防栓使用方法",icon:"🧯",content:"室内消防栓使用步骤：<br><br>🔹 打开消防栓箱门<br>🔹 取出水带，向火场方向铺设<br>🔹 将水带接口连接消防栓出水口<br>🔹 另一端连接水枪<br>🔹 打开阀门，对准火源根部喷射<br><br>⚠️ 一般需要<strong>2人配合</strong>操作<br>⚠️ 水带要避免扭曲打折"},{title:"高层建筑逃生",icon:"🏢",content:"高层建筑火灾逃生要点：<br><br>🔹 <strong>不要乘坐电梯</strong>！<br>🔹 用<strong>湿毛巾</strong>捂住口鼻<br>🔹 弯腰或匍匐前进（烟往上飘）<br>🔹 沿<strong>疏散楼梯</strong>向下撤离<br>🔹 楼道有烟时退回房间等待救援<br>🔹 可用<strong>床单结绳</strong>自救（低楼层）<br>🔹 关闭房门用湿布堵缝隙<br><br>📱 拨打<strong>119</strong>报告位置！"}],flood:[{title:"洪水预警等级",icon:"📊",content:"洪水预警分为四个等级：<br><br>🟢 <strong>蓝色预警</strong>（IV级）：一般洪水<br>🟡 <strong>黄色预警</strong>（III级）：较大洪水<br>🟠 <strong>橙色预警</strong>（II级）：大洪水<br>🔴 <strong>红色预警</strong>（I级）：特大洪水<br><br>收到预警后：<br>🔹 关注天气预报和官方通知<br>🔹 准备应急物资<br>🔹 低洼地区居民做好转移准备"},{title:"城市内涝自救",icon:"🏙️",content:"城市暴雨内涝时：<br><br>🔹 不要在积水中行走（看不清路面）<br>🔹 远离<strong>下水道井盖</strong>（可能被冲开）<br>🔹 远离<strong>电线杆</strong>和变压器<br>🔹 汽车涉水熄火后<strong>立即弃车</strong><br>🔹 被困时向高处转移<br>🔹 拨打<strong>110/119</strong>求助<br><br>⚠️ 积水深度超过<strong>30厘米</strong>不要步行通过！"}],typhoon:[{title:"台风预警信号",icon:"🌀",content:"台风预警四级信号：<br><br>🔵 <strong>蓝色</strong>：24小时内可能受台风影响<br>🟡 <strong>黄色</strong>：24小时内可能受强台风影响<br>🟠 <strong>橙色</strong>：12小时内可能受强台风影响<br>🔴 <strong>红色</strong>：6小时内可能受超强台风影响<br><br>各级别应对：<br>蓝色→关注天气<br>黄色→固定门窗<br>橙色→停止户外活动<br>红色→就近避险"},{title:"台风天居家防护",icon:"🏠",content:"台风来临前：<br><br>🔹 检查并<strong>加固门窗</strong>（贴米字胶带）<br>🔹 收好阳台花盆等<strong>悬挂物</strong><br>🔹 储备<strong>3天</strong>食物和饮水<br>🔹 准备手电筒、充电宝<br>🔹 关注台风实时路径<br><br>台风来临时：<br>🔹 远离窗户<br>🔹 不要外出<br>🔹 停止使用电梯<br>🔹 如在室外立即进入坚固建筑"}],lightning:[{title:"雷电防御指南",icon:"⚡",content:"室内防雷：<br>🔹 关闭门窗<br>🔹 拔掉电器插头（电视、电脑）<br>🔹 不要打电话<br>🔹 不要洗澡（金属管道导电）<br><br>室外防雷：<br>🔹 远离大树、电线杆、铁塔<br>🔹 不要打伞（金属柄）<br>🔹 蹲下，双脚并拢<br>🔹 远离水面（湖、河、海）<br>🔹 手机可以正常使用（不会引雷）"}],landslide:[{title:"泥石流逃生路线",icon:"⛰️",content:"泥石流来临时：<br><br>✅ <strong>向两侧山坡跑</strong>（垂直于泥石流方向）<br>❌ <strong>不要顺着山谷往下跑</strong>（跑不过泥石流）<br>❌ <strong>不要躲在沟谷里</strong><br><br>泥石流前兆：<br>🔹 河水突然断流或变浑<br>🔹 山体出现裂缝<br>🔹 听到轰鸣声<br>🔹 树木倾斜<br><br>⚠️ 泥石流速度可达<strong>60km/h</strong>！"}],snowstorm:[{title:"暴雪天气防护",icon:"🌨️",content:"暴雪防护要点：<br><br>🔹 减少外出，待在室内<br>🔹 外出穿<strong>保暖防滑</strong>衣物<br>🔹 开车<strong>减速慢行</strong>，保持安全距离<br>🔹 准备<strong>融雪剂</strong>或沙子防滑<br>🔹 检查供暖设备<br>🔹 储备食物和饮水<br><br>⚠️ 注意：<strong>失温</strong>比冻伤更危险！体温低于35°C需紧急救治。"}],gas:[{title:"燃气泄漏处置",icon:"🔥",content:"发现燃气泄漏：<br><br>❌ <strong>不要开灯</strong>（电火花引燃）<br>❌ <strong>不要打电话</strong><br>❌ <strong>不要开关电器</strong><br><br>✅ 正确做法：<br>🔹 <strong>轻轻打开门窗</strong>通风<br>🔹 <strong>关闭燃气总阀门</strong><br>🔹 迅速撤离到室外<br>🔹 在安全处拨打<strong>燃气公司电话</strong>或<strong>119</strong><br><br>⚠️ 天然气比空气轻，会向上飘散！"},{title:"燃气安全检查",icon:"🔍",content:"定期检查燃气安全：<br><br>🔹 检查燃气管路是否老化、破损<br>🔹 用肥皂水涂抹接口处检查漏气<br>🔹 观察燃气表是否异常走动<br>🔹 检查灶具是否正常点火<br><br>⚠️ 燃气管路使用寿命一般为<strong>8年</strong><br>⚠️ 建议每<strong>2年</strong>请专业人员上门检查"}],tornado:[{title:"龙卷风的形成",icon:"🌪️",content:'龙卷风是强烈的旋涡状气流：<br><br>🔹 通常在<strong>雷暴云</strong>中形成<br>🔹 温暖湿润气流与冷空气交汇<br>🔹 形成强大的<strong>上升气流</strong><br>🔹 气流旋转加速形成漏斗云<br>🔹 接触地面即为龙卷风<br><br>美国中部的<strong>"龙卷风走廊"</strong>是全球龙卷风最频繁的地区。'},{title:"龙卷风等级",icon:"📊",content:"龙卷风按强度分为<strong>EF0-EF5</strong>级：<br><br>🔹 <strong>EF0</strong>：轻微损坏（风速105-137km/h）<br>🔹 <strong>EF1</strong>：中等损坏（138-178km/h）<br>🔹 <strong>EF2</strong>：较大损坏（179-218km/h）<br>🔹 <strong>EF3</strong>：严重损坏（219-266km/h）<br>🔹 <strong>EF4</strong>：毁灭性损坏（267-322km/h）<br>🔹 <strong>EF5</strong>：难以置信的损坏（>322km/h）<br><br>EF5级龙卷风可以将建筑从地基上卷走！"},{title:"龙卷风来了怎么办",icon:"🏃",content:"<strong>室内：</strong><br>🔹 立即躲到地下室或最内侧小房间<br>🔹 远离窗户<br>🔹 躲在坚固家具下面<br>🔹 用枕头/被子护住头部<br><br><strong>室外：</strong><br>🔹 立即寻找坚固掩体<br>🔹 没有掩体时趴在地上<br>🔹 远离汽车、树木、电线杆<br>🔹 不要试图驾车逃离"},{title:"龙卷风预警信号",icon:"⚠️",content:"龙卷风预警分为三级：<br><br>🟡 <strong>黄色预警</strong>：6小时内可能形成龙卷风<br>🟠 <strong>橙色预警</strong>：2小时内可能出现龙卷风<br>🔴 <strong>红色预警</strong>：龙卷风即将来临<br><br>听到警报后立即进入安全区域！不要等待进一步通知！"}],snowstorm:[{title:"暴风雪的危害",icon:"❄️",content:"暴风雪的主要危害：<br><br>🔹 <strong>能见度极低</strong>：白茫茫一片<br>🔹 <strong>道路结冰</strong>：交通事故频发<br>🔹 <strong>电力中断</strong>：电线被积雪压断<br>🔹 <strong>低温冻伤</strong>：暴露的皮肤会冻伤<br>🔹 <strong>房屋倒塌</strong>：积雪过重压垮屋顶<br><br>暴风雪期间尽量待在室内，不要外出！"},{title:"防冻保暖知识",icon:"🧥",content:"低温环境下防冻要点：<br><br>🔹 穿<strong>多层衣物</strong>（内层排汗、中层保暖、外层防风）<br>🔹 保护<strong>头部、手脚</strong>等容易散热的部位<br>🔹 保持衣物<strong>干燥</strong>（湿衣物散热速度是干衣物的25倍）<br>🔹 喝<strong>热水</strong>保持体温<br>🔹 注意<strong>一氧化碳中毒</strong>（室内烧炭取暖要通风）"}],tsunami:[{title:"海啸的成因",icon:"🌊",content:"海啸主要由以下原因引起：<br><br>🔹 <strong>海底地震</strong>（最主要，占80%）<br>🔹 <strong>海底火山爆发</strong><br>🔹 <strong>海底滑坡</strong><br>🔹 <strong>陨石撞击</strong>（极罕见）<br><br>海啸的特点：<br>🔹 在深海传播速度可达<strong>800km/h</strong><br>🔹 到达浅海时波高急剧增大<br>🔹 不是一波浪，而是<strong>连续多波</strong><br>🔹 第二波可能比第一波更强！"},{title:"海啸预警系统",icon:"📡",content:"太平洋海啸预警系统：<br><br>🔹 由<strong>26个</strong>太平洋沿岸国家共同建立<br>🔹 监测海底地震和潮位变化<br>🔹 地震后<strong>几分钟内</strong>发布预警<br>🔹 通过手机、广播、警报器通知<br><br>中国海啸预警：<br>🔹 <strong>自然资源部</strong>负责发布<br>🔹 关注官方渠道信息<br>🔹 海啸到达前有<strong>10分钟到数小时</strong>的预警时间"}],landslide:[{title:"滑坡的前兆",icon:"⚠️",content:"滑坡前可能出现的征兆：<br><br>🔹 <strong>地面裂缝</strong>：突然出现新的裂缝<br>🔹 <strong>泉水变化</strong>：泉水突然干涸或变浑<br>🔹 <strong>坡体变形</strong>：树木倾斜、墙体开裂<br>🔹 <strong>异常响动</strong>：地下传来轰隆声<br>🔹 <strong>动物异常</strong>：蛇虫大规模迁徙<br><br>发现这些征兆后立即撤离！"},{title:"滑坡与泥石流的区别",icon:"🏔️",content:"<strong>滑坡</strong>：<br>🔹 土体沿滑动面整体下滑<br>🔹 速度相对较慢（几米/天到几米/秒）<br>🔹 通常不涉及大量水<br><br><strong>泥石流</strong>：<br>🔹 含有大量泥沙石块的洪流<br>🔹 速度极快（可达<strong>10m/s</strong>以上）<br>🔹 需要大量水作为载体<br>🔹 破坏力更强<br><br>两者都可能在暴雨后发生！"}],wildfire:[{title:"野火的分类与等级",icon:"🔥",content:"野火（森林火灾）按规模分级：<br><br>🔹 <strong>地表火</strong>：烧地面植被，最常见<br>🔹 <strong>树冠火</strong>：烧树冠，蔓延快<br>🔹 <strong>地下火</strong>：烧泥炭层，最难扑灭<br><br>按规模：小火（<100公顷）、中火、大火<br><br>🔥 中国每年森林火灾数千起，主要发生在<strong>春季和秋季</strong>。"},{title:"野外用火安全",icon:"⛺",content:"野外露营用火注意事项：<br><br>✅ 选择远离树木的空旷地带<br>✅ 准备灭火工具（水、沙子）<br>✅ 用石头围成防火圈<br>✅ 离开时彻底熄灭火源<br>✅ 不要在大风天生火<br><br>❌ 不要在枯草地生火<br>❌ 不要丢弃未熄灭的烟蒂<br>❌ 不要在禁止区域生火<br><br>⚠️ 大多数森林火灾都是人为引起的！"}],sandstorm:[{title:"沙尘暴的形成",icon:"🏜️",content:"沙尘暴的形成条件：<br><br>🔹 <strong>沙源</strong>：干旱荒漠地区<br>🔹 <strong>强风</strong>：提供搬运动力<br>🔹 <strong>不稳定大气</strong>：利于沙尘上升<br><br>中国的沙尘暴主要来源：<br>🔹 <strong>塔克拉玛干沙漠</strong><br>🔹 <strong>巴丹吉林沙漠</strong><br>🔹 蒙古国南部荒漠<br><br>春季（3-5月）是沙尘暴高发期。"},{title:"沙尘暴防护指南",icon:"😷",content:"沙尘暴来临时的防护措施：<br><br>🔹 <strong>外出佩戴口罩</strong>（N95效果最好）<br>🔹 <strong>关闭门窗</strong>，用湿毛巾堵缝隙<br>🔹 <strong>外出后洗脸漱口</strong>，清理鼻腔<br>🔹 <strong>不要在室外晾衣服</strong><br>🔹 <strong>开车开雾灯</strong>，减速慢行<br><br>沙尘暴后：<br>🔹 及时<strong>清洁室内</strong><br>🔹 <strong>检查车辆</strong>空气滤清器<br>🔹 <strong>补充水分</strong>，预防呼吸道疾病"}],extreme_heat:[{title:"极端高温的危害",icon:"🌡️",content:"高温天气的健康风险：<br><br>🔹 <strong>中暑</strong>：头晕、恶心、乏力<br>🔹 <strong>热痉挛</strong>：大量出汗后肌肉痉挛<br>🔹 <strong>热衰竭</strong>：体温升高、血压下降<br>🔹 <strong>热射病</strong>：最严重，体温>40°C，可致命！<br><br>热射病死亡率高达<strong>50%以上</strong>！发现有人中暑要立即急救！"},{title:"防暑降温方法",icon:"🧊",content:"预防中暑的方法：<br><br>🔹 <strong>避免10:00-16:00外出</strong><br>🔹 <strong>多喝水</strong>（不要等到口渴才喝）<br>🔹 穿<strong>浅色、宽松、透气</strong>的衣物<br>🔹 使用<strong>防晒霜</strong>和<strong>遮阳伞</strong><br>🔹 室内开空调（温度设<strong>26°C</strong>左右）<br>🔹 随身携带<strong>防暑药品</strong>（藿香正气水等）<br><br>⚠️ 老人、儿童、户外工作者是高危人群！"}],nuclear:[{title:"核辐射基础知识",icon:"☢️",content:"核辐射的基本概念：<br><br>🔹 <strong>核辐射</strong>：原子核释放的能量<br>🔹 <strong>核泄漏</strong>：核设施受损导致放射性物质释放<br>🔹 <strong>半衰期</strong>：放射性物质衰减一半所需时间<br><br>核泄漏的主要危害：<br>🔹 <strong>外照射</strong>：射线穿透人体<br>🔹 <strong>内照射</strong>：吸入/食入放射性物质<br>🔹 <strong>环境污染</strong>：土壤、水源被污染"},{title:"核事故防护",icon:"🛡️",content:"核事故发生后的防护措施：<br><br>🔹 <strong>进入室内</strong>，关闭门窗和通风<br>🔹 <strong>收听官方广播</strong>，听从指挥<br>🔹 <strong>不要外出</strong>，等待解除警报<br>🔹 储备<strong>瓶装水和食物</strong><br>🔹 如果在室外，<strong>遮住口鼻</strong>快速进入室内<br>🔹 <strong>脱去外衣</strong>密封在塑料袋中<br>🔹 <strong>彻底冲洗身体</strong><br><br>⚠️ <strong>不要盲目服用碘片</strong>，需在专业指导下使用！"}]},_merged:!1,_mergeArticles(){if(!this._merged){for(var catId in this._merged=!0,this.extraArticles)this.articles[catId]||(this.articles[catId]=[]),this.articles[catId]=this.articles[catId].concat(this.extraArticles[catId]);if("undefined"!=typeof EXTRA_ENCYCLOPEDIA)for(var catId2 in EXTRA_ENCYCLOPEDIA)this.articles[catId2]||(this.articles[catId2]=[]),this.articles[catId2]=this.articles[catId2].concat(EXTRA_ENCYCLOPEDIA[catId2]);if("undefined"!=typeof FINAL_ENCYCLOPEDIA)for(var catId3 in FINAL_ENCYCLOPEDIA)this.articles[catId3]||(this.articles[catId3]=[]),this.articles[catId3]=this.articles[catId3].concat(FINAL_ENCYCLOPEDIA[catId3])}},render(){this._mergeArticles();const container=document.getElementById("encyclopediaCategories");container&&(container.innerHTML=this.categories.map(cat=>`\n      <div class="encyclopedia-category-card" onclick="EncyclopediaEngine.showCategory('${cat.id}')" style="--cat-color:${cat.color}">\n        <span class="category-icon">${cat.icon}</span>\n        <span class="category-name">${cat.name}</span>\n        <span class="category-count">${(this.articles[cat.id]||[]).length}篇</span>\n      </div>\n    `).join(""))},showCategory(catId){const cat=this.categories.find(c=>c.id===catId),articles=this.articles[catId]||[];if(!cat||!articles.length)return;let html=`<div class="encyclopedia-header" style="background:linear-gradient(135deg,${cat.color}33,${cat.color}11)">\n      <span style="font-size:48px">${cat.icon}</span>\n      <h2 style="color:${cat.color};margin:8px 0 0">${cat.name}百科</h2>\n      <p style="color:var(--text-secondary)">${articles.length} 篇知识文章</p>\n    </div><div class="encyclopedia-articles">`;articles.forEach((article,i)=>{html+=`\n        <div class="encyclopedia-article-card" onclick="EncyclopediaEngine.showArticle('${catId}',${i})">\n          <span class="article-icon">${article.icon}</span>\n          <span class="article-title">${article.title}</span>\n          <span class="article-arrow">→</span>\n        </div>`}),html+='</div>\n      <button class="btn btn-secondary" onclick="EncyclopediaEngine.showCategory(\'${catId}\')" style="margin-top:16px">← 返回分类</button>';const container=document.getElementById("encyclopediaContent");container&&(container.innerHTML=html)},showArticle(catId,index){const cat=this.categories.find(c=>c.id===catId),articles=this.articles[catId]||[],article=articles[index];if(!cat||!article)return;const html=`\n      <div class="encyclopedia-reader">\n        <div class="reader-header" style="border-left:4px solid ${cat.color}">\n          <span>${cat.icon}</span>\n          <div>\n            <div style="font-size:12px;color:var(--text-dim)">${cat.name}</div>\n            <div style="font-size:18px;font-weight:700">${article.title}</div>\n          </div>\n        </div>\n        <div class="reader-body">${article.content}</div>\n        <div class="reader-nav">\n          ${index>0?`<button class="btn btn-secondary" onclick="EncyclopediaEngine.showArticle('${catId}',${index-1})">← 上一篇</button>`:"<div></div>"}\n          <span style="color:var(--text-dim);font-size:14px">${index+1} / ${articles.length}</span>\n          ${index<articles.length-1?`<button class="btn btn-primary" onclick="EncyclopediaEngine.showArticle('${catId}',${index+1})">下一篇 →</button>`:`<button class="btn btn-primary" onclick="EncyclopediaEngine.showCategory('${catId}')">返回目录</button>`}\n        </div>\n      </div>`,container=document.getElementById("encyclopediaContent");container&&(container.innerHTML=html),void 0!==GameState&&(GameState._data.coins+=5,GameState.save())}};
